var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"보안국은 건국기념전당 앞에서 발생한 폭발 사고가 반정부 단체인 <color=#ffd34c>순혈지식 연대</color>의 계획적인 사보타주라고 발표했습니다.","JPN":"保安局は、建国記念館の前で発生した爆発事故が反政府団体である<color=#ffd34c>純血知識連帯</color>の計画的なサボタージュだと発表しました。","ENG":"The Department of National Security has announced that the explosion in front of the National Foundation Hall was a terrorist attack planned by the anti-government organization <color=#ffd34c>Pureblood Knowledge Regiment</color>","TWN":"安全局表示，於建國紀念堂前發生的爆炸事件，是反政府團體 <color=#ffd34c>純血知識年代</color>有計畫性的攻擊行動。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"건국절 기념 공연의 관객들을 노린 이 사고로 인해 수백 명의 사망자가 발생하였으며…….","JPN":"建国記念公演の観客を狙ったこの事件により、数百人が死亡し……","ENG":"Hundreds of people in attendance at the National Foundation Day event were killed.….","TWN":"此次的攻擊，造成數百位來欣賞國慶表演的觀眾死亡……"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"지난번 사태에 휘말렸던 음악가, 루이제 슈나이더 씨의 의식이 회복되었다는 소식입니다.","JPN":"以前の事態に巻き込まれた音楽家、ルイーゼ・シュナイダー氏が意識を取り戻しました。","ENG":"It is reported that Louise Schneider, a famous musician who attended the performance, has regained consciousness.","TWN":"捲入上次事件的音樂家 露易絲·修奈德，據說已經恢復意識。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"주치의는 슈나이더 씨가 중추신경 손상으로 하반신이 마비되었다고 전해, 반정부 단체에 대한 국민의 공분을 불러일으킨 바 있습니다.","JPN":"主治医はシュナイダー氏が中枢神経の損傷で下半身が麻痺した事実を伝え、反政府団体への国民の怒りを呼び起こしました。","ENG":"The doctors say she has been paralyzed from the waist down, sparking public outrage towards the anti-government forces.","TWN":"主治醫生表示，修奈德的中樞神經受損，導致下半身麻痺。而反政府團體的作為，已經引發全國人民的憤怒。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"뉴스 중의 뉴스, 진짜 뉴스를 전하는 <color=#ffd34c>국민의 노래</color>.","JPN":"ニュースの中のニュース、本当のニュースをお伝えする<color=#ffd34c>民の歌</color>。","ENG":"The news of the news! <color=#ffd34c>The Voice of the People</color>, reporting the real truth.","TWN":"重磅新聞，只報導真正新聞的<color=#ffd34c>人民之聲</color>。"},"stage":{"bg":"GRONIA_STREET","bgm":"UI_CONSORTIUM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘 영상에서는 현장에서 살아남은 슈나이더 모녀에 대해 다루고자 합니다.","JPN":"今日の動画では、現場で生き残ったシュナイダー親子について話します。","ENG":"In today's video, we're going to break down the news on two survivors, Louis Schneider and her daughter.","TWN":"今天想要討論的內容，是有關於在爆炸事件中倖存下來的修奈德母女。"},"stage":{"bg":"GRONIA_STREET","bgm":"UI_CONSORTIUM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"이번 내용, 끝까지 봐도 후회 안 하실 겁니다. 다 보시고 난 뒤 구독과 좋아요 잊지 마세요.","JPN":"今回の内容、最後まで見ても後悔はしないはずです。視聴後、チャンネル登録とイイね！をお忘れなく。","ENG":"You’ll regret it if you don’t watch till the end! And don’t forget to like and subscribe for amazing content!","TWN":"一定要看到最後，保證你不會後悔！看完後別忘記按讚加訂閱喔！"},"stage":{"bg":"GRONIA_STREET","bgm":"UI_CONSORTIUM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"루이제 슈나이더, 사진으로 보시다시피 처음 데뷔할 때부터 그 미모로 호평을 받았는데요.","JPN":"ルイーゼ・シュナイダー、写真でおわかりのように、デビューした時からその美しさで話題となりました。","ENG":"Louise Schneider, as you can see from this picture, has been well known for her beauty ever since she debuted.","TWN":"露易絲·修奈德，從照片上可以看到，從她出道開始，就因她的美貌而受到大家喜愛。"},"stage":{"bg":"GRONIA_STREET","bgm":"UI_CONSORTIUM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"저희 넷튜브 채널을 통해 접촉해 온 제보자에 따르면, 반군들에게 딸과 자신의 안전을 대가로 몸을……","JPN":"我らのネットチューブチャンネルを通じて接触してきた情報提供者によりますと、娘と自分の身の安全の見返りに反乱軍に身を……","ENG":"And according to an informant connected with our NetTube channel, in exchange for her and her daughter’s safety, she was forced to sell her body...","TWN":"但是我們收到內幕消息，據說她以自己和女兒的安全為代價，獻身給叛軍……"},"stage":{"bg":"GRONIA_STREET","bgm":"UI_CONSORTIUM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……그래서 확보한 건 결국 그 악보뿐이라는 건가?","JPN":"……それで、確保したのは結局その楽譜だけなのか？","ENG":"...Anyways, is the musical score the only thing you secured?","TWN":"……所以你們只有找到那個樂譜嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네, 침식체는 사살 직후 신체가 붕괴하더군요.","JPN":"はい。侵食体は射殺直後に体が崩壊しました。","ENG":"That’s correct. The Corrupted Object collapsed immediately after being shot.","TWN":"對，射殺侵蝕體後，它的身體就開始解體。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"인간의 생체 조직 일부가 남은 걸로 봐선, 변이가 급격하게 진행된 모양이에요.","JPN":"人間の生体組織が一部残ってるところを見ると、急激に変異したようです。","ENG":"Given that some of the human biological tissue remains, the mutation seems to have occurred only recently.","TWN":"從它還留有部分人體組織來看，應該是在很緊急的情況下變異的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"침식 증후군으로 인한 말로라기에는 석연치 않군.","JPN":"侵食症候群による末路にしては釈然としないな。","ENG":"But we can’t be sure due to the Corruption Syndrome.","TWN":"但這也無法解釋是因為侵蝕症候群而造成的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L30_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그 침식지대의 CSE 레벨은 2를 넘지 않아. 그런데도 그 며칠 사이 2종 침식체가 되었다면……","JPN":"あの侵食地帯のCSEレベルは2に満たない。なのに、この何日間で第2種侵食体になったのなら……","ENG":"That Corrupted Area’s CSE level has never exceeded level 2. And yet, just a few days ago, a Category 2 Corrupted Object...","TWN":"那個侵蝕地帶的CSE等級不到2，要在這短的時間內變成2類侵蝕體……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다른 고준위 침식파에 노출되었거나, 누군가가 인위적으로 저지른 짓이겠죠.","JPN":"他の高レベルの侵食波にさらされたか、あるいは誰かが人為的に変異させたのでしょう。","ENG":"It must be due to exposure to other high-level Corruption rays, or someone is artificially creating it.","TWN":"除非是暴露在高侵蝕波中，或是人為造成的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"강경파 반군과 협력하던 제프티 바이오테크에서 침식체를 병기로 활용하려는 움직임이 있었습니다.","JPN":"強硬派の反乱軍と協力していたジェフティ・バイオテックで、侵食体を兵器に使おうとする動きがありました。","ENG":"There was a movement to use Corrupted Objects as a weapon at Jehuty Biotech, which was cooperating with rebels from the hardliners.","TWN":"之前和強硬派叛軍合作過的傑夫堤生物科技，就曾經將侵蝕體作為武器使用。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 연장선상이라고 하면 퍼즐이 맞아 떨어져요. 클림트의 정체를 비롯해 더 적극적인 조사가 필요합니다.","JPN":"その延長なのだと考えれば理にかないます。クリムトの正体を始めとしてもっと積極的に調査する必要があります。","ENG":"The pieces of the puzzle all fit. Still, further investigation is needed, including into Klimt's real identity.","TWN":"這樣事件的拼圖就可以拼湊起來。從克里姆的真實身分開始，需要更積極地展開調查。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯嗯……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"일리는 있지만 당장은 건국절 행사가 우선이야. 호들갑을 떨면서 대처할 필요까지는 없어.","JPN":"一理あるが、今は建国記念日が先だ。大げさに対処するまでの必要はない。","ENG":"It may make sense, nevertheless, the National Foundation Day event takes priority. You don’t have to worry about that right now.","TWN":"話是有道理，但現在當務之急是先把國慶典禮辦好，不需要大動作處理。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"국장님. 전황에 악영향을 끼칠 수도 있어요.","JPN":"局長。戦況に悪い影響が出るかもしれません。","ENG":"Chief, it could negatively impact our current situation.","TWN":"部長，這樣恐怕會對局勢有不好的影響！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트……. 자네에게 해외 임무를 주로 맡겼던 건 그 충동적인 면 때문이야.","JPN":"レヴナント……君に主に海外の任務を任せたのは、その衝動的な一面のせいだ。","ENG":"Revenant... It’s because of this instinctual side of yours that I’ve entrusted you mainly with overseas missions.","TWN":"亡靈……我之所以都讓你負責海外的任務，就是因為你太容易衝動。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"반군과 엮일 구석이 보이면 이상하리만큼 냉정함을 유지하지 못해.","JPN":"反乱軍と絡む余地があると、おかしいくらいに冷静さを失う。","ENG":"For whatever the reason, you can’t seem to maintain your composure when it comes to the rebels.","TWN":"事情只要牽扯到叛軍，你就會失去理性。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"악보는 자네가 직접 보안국으로 가져오도록 해.","JPN":"楽譜は君が直接保安局に持ってくるように。","ENG":"I want you to submit the full score to the National Security in person.","TWN":"樂譜你就直接拿到安全局來，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"파레마 건에 대해서도 자네와 단둘이 할 얘기가 있으니까.","JPN":"パレマの件についても君と二人きりで話したいからな。","ENG":"Furthermore, I need to have a conversation with you about the Parema operation.","TWN":"波雷馬的事我也有話要跟你說。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"오늘은 우선 휴식을 취하게. 나는 이 사안을 어떻게 처리할지 관련자들과 논의해야겠어.","JPN":"今日はまず休め。私はこの案件をどう処理するか、関係者と議論してみよう。","ENG":"For now, call it a day. I need to discuss how to handle this with those related to the matter.","TWN":"你今天就先休息吧，至於這件事要如何處理，等我跟相關人士討論過後再說。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……잠시만요.","JPN":"……待ってください。","ENG":"...Wait.","TWN":"……先等一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"음? 뭔가?","JPN":"うん？　どうした？","ENG":"Hm? What is it?","TWN":"嗯？還有什麼事？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이 악보에 적힌 곡, 행사 당일의 세트리스트에는 오르지 않았어요.","JPN":"この楽譜の曲、行事当日のセットリストには載ってなかったんです。","ENG":"The song of this score was not on the setlist on the day of the event.","TWN":"樂譜上寫的歌，並沒有出現在國慶日當天的曲目上。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그리고…… 제 기억이 맞다면……","JPN":"そして……私の記憶に間違いがなければ……","ENG":"And... If I remember correctly...","TWN":"而且……若我沒記錯……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"예상대로라네.","JPN":"君の予想どおりだ。","ENG":"That’s to be expected.","TWN":"你猜得沒錯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그건 자네 어머니가 준비하던 미발표 곡이야. 당일 공연 때 공개될 예정이었지.","JPN":"それは君の母親が準備していた未発表の曲だ。当日の公演で公開されるはずだった。","ENG":"It’s an unreleased piece that your mother was working on. It was set to be revealed at the day of the concert.","TWN":"那是你媽媽未發表的曲目，原本是預計在表演當天發表的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 클림트가 저희 집에 방문했던 것도, 설마 악보 때문이란 말인가요?","JPN":"それじゃあクリムトが私の家に訪れたのも、まさか楽譜のせいなんですか？","ENG":"So Klimt visited my house because of that piece?","TWN":"難道克里姆會找到我家來，就是因為這個樂譜嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그럴 가능성도 배제할 수 없지.","JPN":"その可能性も無視できない。","ENG":"We can’t rule out the possibility.","TWN":"不排除有這個可能。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"알다시피, 그건 자네 어머니가 반군의 사보타주에 휘말리고 나서 준비하던 곡이야.","JPN":"知っていると思うが、それは君の母親が反乱軍のサボタージュに巻き込まれた後に準備していた曲だ。","ENG":"As you know, it’s the piece your mother was in the middle of working on after the terrorist attack occurred.","TWN":"你也知道，那是你媽媽在捲入叛軍恐怖事件後才寫的曲子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"정신질환에 시달리던 데다가 내전으로 인해 잊혀 버렸지만…….","JPN":"精神病を病んでいた上に、内戦のせいで忘れられたが……","ENG":"It may have been largely forgotten because of her mental illness and because of the civil war, but even so...","TWN":"雖然你媽媽受精神疾病所苦，又因為內戰而被遺忘……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"곡의 주제는 화해와 평화라더군.","JPN":"曲の主題は和解と平和だそうだな。","ENG":"The theme of the piece was reconciliation and peace.","TWN":"但曲子的主題是關於和平。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래요. 한동안은 정신이 온전하셨으니까요.","JPN":"そうです。しばらくは正気でしたので。","ENG":"Yes. Her mind was able to stay healthy for a while.","TWN":"我知道，我媽有一陣子精神狀況很穩定。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 이상한 소문들만 퍼지지 않았더라도…….","JPN":"あの変な噂さえなかったら……","ENG":"If only those rumors didn’t spread...","TWN":"要不是因為那個奇怪的傳言……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"너무 애석해하지 말게. 자네 어머니를 안타깝게 여긴 여론 덕분에 반정부 단체를 억제할 수 있었어.","JPN":"そう悲しむな。君の母親を気の毒と考えたマスコミのおかげで反政府団体を抑えられたんだ。","ENG":"Don’t beat yourself up too much about that. Thanks to that, we were able to use the resulting public outrage about what happened to your mother and suppress the anti-government organization.","TWN":"你也別太糾結於此，幸虧輿論是站在你媽媽那邊，才能打壓反政府團體。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"관리실패만 일어나지 않았다면……. 우리는 지금과 전혀 다른 나라에 살고 있었을 거야.","JPN":"管理失敗さえなければ……私たちは今とはまったく違う国に住んでいただろう。","ENG":"If it wasn’t for the Administration Failure...we would be living in a completely different country than we are now.","TWN":"要不是發生管理失敗……我們會生活在與現在完全不同的國家裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"말씀하시는 바는 이해합니다만, 그렇다고 그런 지저분한 소문을 퍼뜨린 자들을 용서하고 싶은 마음은 없습니다.","JPN":"お言葉はわかりますけど、それでもあんな汚い噂をバラまいた者たちを許す気はありません。","ENG":"I understand what you’re saying, sir. But I still can’t forgive the ones who spread such horrible rumors.","TWN":"我明白你說的，但我還是無法原諒那些可惡的造謠者！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"……好吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"하긴, 지나간 일을 가지고 얘기할 필요는 없지. 이만 쉬게.","JPN":"まあ、終わったことであれこれ話す必要はないだろう。もう休め。","ENG":"Maybe you're right, but what’s happened, happened. Get some rest.","TWN":"就先這樣吧，都已經是過去的事，也沒什麼好說的，去休息吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"상사랑 얘기는 잘 됐나요, 레버넌트 씨? 분위기가 심상치 않던데요.","JPN":"上司との話はうまくいったんですか？　レヴナントさん。あんまりいいムードじゃなかったみたいですけど。","ENG":"How’d the talk go with your boss, Revenant? The atmosphere looked pretty tense.","TWN":"亡靈小姐，你和長官談得還好嗎？覺得氣氛有點怪怪的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"두 사람 앞에선 레아라고 불러.","JPN":"二人の前ではレアって呼んで。","ENG":"Call me Leah in front of those two.","TWN":"在他們面前叫我蕾亞。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"보통은 이런 편이야. 심각한 주제로 대화할 때가 대부분이니까.","JPN":"普段からこうなの。ほとんど深刻な案件で電話するから。","ENG":"It’s always like that. We always talk about serious topics.","TWN":"我們常這樣，因為每次講電話，幾乎都是談一些很嚴肅的事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보안국 요원이라는 것도 참 피곤한 인생이네요.","JPN":"保安局エージェントの人生って本当楽じゃないですね。","ENG":"Being an agent of the National Security seems like a pretty rough life.","TWN":"安全局幹員的人生也是很不容易呢～"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러는 중사는 왜 집까지 따라왔어?","JPN":"そういう軍曹はなんで家までついてきたの？","ENG":"What about you, Sergeant? Why are you following me home?","TWN":"不過中士，你跟我回家幹嘛？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"설마 숙박비도 지원 안 해 줄 거라고는 예상 못했거든요.","JPN":"まさか宿泊費も支援してくれないなんて予想もしなかったんで。","ENG":"Well, I thought there’s no way I wouldn’t be provided any accommodations!","TWN":"因為我沒想到沒有住宿津貼。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"수도 방어 부대에 재워 달라고 연락했더니 무슨 헛소리냐는 핀잔이나 듣고.","JPN":"首都防御部隊に寝かしてくれって連絡したら、ふざけるなって叱られるし。","ENG":"But when I called the Capital Guard, asking for a place to stay, they just laughed at me, saying I couldn’t be serious!","TWN":"我有問首都防衛隊可不可以收留我一晚，結果被臭罵一頓，問我在胡說八道什麼。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아무리 그래도 수훈자인데 하루치 숙박비가 없는 거야?","JPN":"いくらなんでも受勲者なのに一泊分の宿泊費もないの？","ENG":"What? You’re an awarded veteran with a medal and you have no money for accommodations?","TWN":"你好歹也是授勳者，身上連一天的住宿費都沒有嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그건…… 으으음…… 뭐라고 해야 할지…….","JPN":"それは……ううん……何ていうか……","ENG":"That’s... Ummm... I don’t even know what to say.","TWN":"這個嘛……呃……該怎麼說呢……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"국경 넘으려고 브로커에게 있는 돈 다 갖다 줬다고 하면 가만 안 있겠지?","JPN":"国境を越えようと思ってブローカーにありったけのお金を渡したって言ったら、ただじゃ済まないよね？","ENG":"If I told her I gave all my money to smugglers to get me out of the country, she wouldn’t let me get away with it, right?","TWN":"總不可能跟你說，我把錢都給了人蛇仲介吧？你知道還會放過我嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"분명……","JPN":"きっと……","ENG":"Definitely...","TWN":"你一定會……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"크헤헤, 이 앙증맞은 매국노 같으니. 보안국이 자랑하는 특별 심문 코스를 맛보여 주지.","JPN":"クヘヘ、このかわいい売国奴め。保安局自慢の特別尋問コースを味わわせてあげるわ。","ENG":"Phaw, How dare you, you villainous traitor! Prepare yourself, for the National Security’s ultimate interrogation technique!","TWN":"哼哼哼，年紀輕輕的學人家做賣國賊！我就讓你嚐嚐安全局最引以為傲的問訊套餐吧！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아이고, 목숨만 살려 주십쇼! 다 먹고 살자고 하는 짓 아니겠습니까요!","JPN":"おねがいします！！　命だけはごかんべんを！！　それもこれも食べていくために仕方なかったんです！！","ENG":"Oh no! Please, have mercy! I only did what I did to put food on the table!","TWN":"哎呀～大人饒命啊！我也是為了求生存的嘛！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……아, 속 쓰려. 위에 구멍 날 것 같아.","JPN":"……あ、お腹痛い。胃に穴が開きそう。","ENG":"...Ah, my heart can’t take any more of this...","TWN":"……嗚，想到就覺得胃痛！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"고향에 부모님이 계세요. 배급도 잘 안 나오는 시골이라 돈이라도 부쳐 줘야 하거든요.","JPN":"故郷に両親がいるんですが。配給もあまりよく配られない田舎なんで、お金でも送らないとダメなんです。","ENG":"My parents are still living out in my hometown. They don’t distribute many rations out there, so I have to send them money from time to time.","TWN":"因為我爸媽住在老家，鄉下地方配給也不多，所以我有錢都會寄回家。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아하. 수도 출신이 아니었구나.","JPN":"へえ。首都生まれじゃなかったんだ？","ENG":"Oh! So you’re a country girl.","TWN":"原來如此，你也不是在首都土生土長的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇다면 어쩔 수 없지. 당분간은 우리 집에서 지내.","JPN":"それなら仕方ないね。しばらくウチで泊ってもいいよ。","ENG":"If that’s the case, no worries! Feel free to crash at my place.","TWN":"那好吧，你就暫時住在我家吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……의외로 선뜻 허락해 주시네요.","JPN":"……意外とすんなり許可してくれるんですね。","ENG":"...Wow, you’re actually going to let me stay at your home?","TWN":"……沒想到你答應得這麼爽快。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후훗. 당연하지. 같이 흙먼지 들이마시면서 싸운 파트너인걸.","JPN":"ふふっ。当たり前でしょ？　一緒に土埃吸いながら戦ったパートナーだもん。","ENG":"Of course! We’re partners after all.","TWN":"呵呵，那還用說，誰叫我們是一起並肩作戰的夥伴。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"파트너……?","JPN":"パートナー……？","ENG":"P-Partners...?","TWN":"夥伴……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래, 파트너. 입에 안 붙으면 전우라고 해도 되고.","JPN":"そう、パートナー。気まずかったら戦友でもいいよ。","ENG":"That’s right. Partners. If you don’t like that word, you can call us comrades.","TWN":"對啊，夥伴，還是你不習慣的話，也可以說是戰友。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아, 일 얘기 끝나려면 아직 멀었어?","JPN":"レア、仕事の話はまだ？","ENG":"Leah, are you almost done with your work talk?","TWN":"蕾亞，你事情還沒談完嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"온몸이 먼지투성이잖아. 얼른 씻어야지.","JPN":"全身埃まみれじゃない。早くお風呂に入って。","ENG":"Your body’s covered in dirt. Hurry up and get yourself cleaned up.","TWN":"看你全身髒兮兮的，還不趕快沖洗一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"하여튼 집에선 늦장꾸러기에 게으름뱅이라니까.","JPN":"まったく、家ではもたもたしてるし、なまけ者なんだから。","ENG":"Leah really is pretty lazy around the house.","TWN":"你在家就是這麼不修邊幅，又髒又懶！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응, 레아 말대로 귀여운 손님이 오셨네…….","JPN":"うん、レアの言うとおりかわいいお客さんが来たのね……","ENG":"Ahh, Leah brought a pretty guest home...","TWN":"嗯嗯，蕾亞說會帶一位可愛的客人會來……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"오늘 식사는……. 맛있게 차려야겠어요…….","JPN":"今日の食事は……美味しいものを作らないとね……","ENG":"I’ll need to make something special... tonight for dinner…","TWN":"那……今要多煮幾道菜……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알겠어, 안젤라. 곧 들어갈게.","JPN":"わかったよ、アンジェラ。すぐ入る。","ENG":"Okay, Angela. We’ll be in soon.","TWN":"好啦，安潔拉，我馬上去洗。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사, 갈아입을 옷은 있어?","JPN":"軍曹、着替えはある？","ENG":"Sergeant, you have a change of clothes?","TWN":"中士，你有衣服可以替換嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네? 저도 같이 들어가요?","JPN":"え？　私も一緒に入るんですか？","ENG":"Wait? I’m showering with you?","TWN":"嗯？我也一起去洗嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"타나베린이 시골보다 사정이 낫긴 해도, 돌아가면서 씻을 만큼 사치 부릴 정도는 아냐.","JPN":"タナベリンが田舎よりはマシでも、贅沢に一人ずつお風呂に入れるほどではないからね。","ENG":"Tanaberin’s situation might be better than the countryside’s, but not enough to take your own showers.","TWN":"達那貝林的情況是比鄉下好，但也沒有奢侈到可以輪流洗澡好嗎！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"씻다가 언제 물이 끊길지 모르거든. 씻을 수 있을 때 몰아서 씻어야지.","JPN":"いつ断水になるかわからないからさ。できる時にお風呂に入らないと。","ENG":"You never know when the water will get turned off. So when the water’s working, we all need to wash together.","TWN":"誰知道會不會洗到一半突然停水，當然要趁有水的時候，趕快一起洗！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"갑자기 군 병원이 그리워지는데요…….","JPN":"急に軍病院が恋しくなりました……","ENG":"Suddenly, I find myself missing that military hospital...","TWN":"突然有點想念軍醫院……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"어때, 물 온도는? 너무 뜨겁지는 않아?","JPN":"湯加減はどう？　熱すぎない？","ENG":"How’s the water temperature? Not too hot?","TWN":"水溫還可以嗎？會不會太燙？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네. 입대할 때 느꼈지만 이렇게나마 씻는 게 어디냐 싶네요.","JPN":"はい。入隊の時もそうでしたけど、こうやってお風呂に入れるだけでも贅沢です。","ENG":"It’s fine. At least I’m thankful for the fact that I’m able to take a shower like this.","TWN":"水溫可以，我進到部隊時就有這種感覺，怎麼會是這樣洗澡的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안면 튼 지도 얼마 안 된 사람이랑 알몸으로 있다는 수치심 정도는 깜빡해 버렸다고나 할까요.","JPN":"知り合ったばかりの人と全裸でいるっていう恥ずかしさなんて、一瞬忘れてたというか。","ENG":"Ugh. I forgot how embarrassing this is, being naked with something you haven’t even known for that long.","TWN":"跟一個見沒幾次面的人坦誠相見，連羞恥兩個字都忘記怎麼寫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후훗. 꽤나 의식하네.","JPN":"ふふっ。結構意識するのね。","ENG":"Fuu fuu... You’re so self-conscious.","TWN":"呵呵，你還會在意這種事喔？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"혹시 동성 취향이야?","JPN":"もしかして同性が好きとか？","ENG":"Wait a second... Are you into girls?","TWN":"難道你喜歡女生嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"글쎄요. 취향을 단언할 만큼 남한테 진지하게 관심 가져 본 적은 없어서요.","JPN":"どうでしょうね。断言できるほど本気で他人に興味を持ったことがないですから。","ENG":"I don’t know. I’ve never been attracted to someone enough to know.","TWN":"我也不知道，因為我從來沒有喜歡過誰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"남들한테 한눈 팔기에는 하루하루 살아남기도 빠듯했고요.","JPN":"毎日生き延びるのにギリギリで、そんな暇なかったです。","ENG":"It was so difficult just to get by day by day, I never really had any time for that kind of stuff.","TWN":"每天光是要活下去就已經很辛苦，哪還有心思花在別人身上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하긴. 이 나라 사람들은 대부분 그렇지.","JPN":"確かに。この国の人は たいていそうよね。","ENG":"Fair enough. I guess most people in this country are in the same situation.","TWN":"也對，這個國家的人應該大部分都是如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"침식체 군집이라도 나타났나 보네. 한동안 뜸하긴 했지.","JPN":"侵食体の群れでも現れたのかな？　最近まばらだったし。","ENG":"Sounds like a cluster of Corrupted objects has been detected. It’s been a while.","TWN":"可能是有侵蝕體出現，有段時間比較少出現的說。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……레버넌트 씨.","JPN":"……レヴナントさん。","ENG":"...Revenant.","TWN":"……亡靈小姐。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"What’s up?","TWN":"幹嘛？"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"등에, 상처가…….","JPN":"背中に、傷が……","ENG":"Those scars... On your back...","TWN":"你背上的傷……"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아. 신경 쓰지 마. 침식체가 아니라 엄마가 낸 거니까.","JPN":"ああ。気にしないで。侵食体じゃなくてお母さん。","ENG":"Ah. Don’t worry about those. Those aren’t from a Corrupted Object or anything. My mom gave me those.","TWN":"喔～這沒什麼啦，這不是侵蝕體弄的，是我媽抓的。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어머니요? 그 휠체어 타고 계시던 분 말이에요?","JPN":"お母さん？　あの車椅子に座ってた方ですか？","ENG":"Your mom? That woman in a wheelchair?","TWN":"你媽媽？那位坐在輪椅上的女士？"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응. 과도한 스트레스로 인한 정신질환이래. 증상만 보면 영락없는 치매야.","JPN":"うん。ストレス過剰による精神病だって。症状を見れば間違いなく認知症だよ。","ENG":"Yup. The doctors said it’s because of a mental illness triggered by the extreme stress her dementia gives her.","TWN":"嗯，她因為壓力過大導致精神疾病，看症狀很明顯就是失智症。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"숨겨 놓은 딸을 내놓으라면서, 이렇게 등을 그어댔지.","JPN":"隠している娘を出せって、こうやって背中を引っかいたの。","ENG":"She screamed at me telling me to give her back her daughter while doing this to my back.","TWN":"她一邊說把我女兒交出來，一邊把我的背抓成這樣。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 날은 너무 힘들어서……. 엄마를 죽인 다음에 나도 죽으려고 했어.","JPN":"その日は辛すぎて……お母さんを殺して私も死のうとしたんだ。","ENG":"At that terrible day... I planned to kill my mom and then myself.","TWN":"那天我真的好累……甚至想先殺死媽媽後，我再自殺。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그걸 막아 준 사람이 아까 본 안젤라야.","JPN":"それを止めてくれたのがさっき会ったアンジェラ。","ENG":"The one who stopped me was Angela, the girl you met earlier.","TWN":"而阻止這件事發生的人，就是你剛才看到的安潔拉。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……그래서 첫눈에 반해 동성 취향이 됐다는 결론인가요?","JPN":"……それで一目惚れして同性に目覚めたんですか？","ENG":"...And when you first saw her, you developed an interest in girls?","TWN":"……所以你對她一見鍾情，然後就喜歡上女生喔？"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후훗. 그게 그렇게 이어지나?","JPN":"ふふっ。そう繋がる？","ENG":"Fuu fuu. Is that what you think?","TWN":"呵呵，是這樣說嗎？"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"마저 씻고 나와, 중사. 식사는 다 같이 모여서 해야지.","JPN":"先に上がるから洗ってきて、軍曹。食事はみんなでしないと。","ENG":"Finish washing up, Sergeant. We’re eating dinner as a family.","TWN":"趕快洗完出來吧，中士。吃飯的時候一定要大家聚在一起吃。"},"stage":{"bg":"HARMONY_02","bgm":"CUTSCENE_SHOWER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"정지, 정지!","JPN":"止まれ、止まれ！","ENG":"Stop, stop!","TWN":"停車，停車！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"이 수송차량, 지금 어디로 가는 거지? 소속과 목적지를 밝혀라.","JPN":"この輸送車、どこへ向かう？　所属と目的地を言え。","ENG":"Where is this transport headed? Identify yourselves.","TWN":"這台運輸車現在是要開去哪裡？說出所屬和目的地！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……. 저 소리 안 들리십니까?","JPN":"へ、へへ……あの音、聞こえませんか？","ENG":"Hey, hey... Can you hear that sound?","TWN":"嘿嘿嘿……你沒聽到聲音嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"주거지역에 기어 들어온 침식체가 없는지 살펴보러 온 겁니다.","JPN":"住居区域へ入ってきた侵食体がないか調べに来たんですよ。","ENG":"We’re here to see if a Corrupted Object has made it into the residential area.","TWN":"我們要去看居住區那裡是不是有侵蝕體入侵。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"자, 여기 우리 회사 명함이니 받아 두시고.","JPN":"どうぞ、うちの会社の名刺、受け取ってください。","ENG":"Here are our company’s business cards.","TWN":"這是我們公司的名片，請收下。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"따로 쓰시라고 봉투에 두둑하게 넣어 뒀습니다.","JPN":"チップを封筒に厚めに入れときました。","ENG":"I even put some nice “stuff” in a separate envelope for you.","TWN":"信封裡是一點小意思，儘管拿去用。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"크흠…….","JPN":"こほん……","ENG":"Ahem...","TWN":"咳咳……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"이런 푼돈으로 검문을 피하려고 들어? 전원 당장 하차한다.","JPN":"こんな小銭で検問をパスしようとしたのか？　全員、すぐ車から降りろ。","ENG":"You think you can avoid an inspection for so little? Everyone, get out of the vehicle at once.","TWN":"這點錢就想打發我們？車上的人都給我下車！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"아, 저기. 그러시지 않는 게…….","JPN":"あ、あの。そうしない方が……","ENG":"Oh, come on now. There’s no need for...","TWN":"哎唷～不要這樣……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"왜 그러지? 뭐가 문제야?","JPN":"どうした？　何かあるのか？","ENG":"What’s going on? Is there a problem?","TWN":"發生什麼事？有什麼問題嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그, 그게 말이지, 나리. 여기 군인 분들이 우리 차를 좀 살펴 봐야겠다고 하시네.","JPN":"そ、それがさ、旦那。この軍人さん、うちの車を確認するっていうんだ。","ENG":"W-well... You see... These fine soldiers here say they need to inspect our vehicle.","TWN":"就…他們說要查我們的車子。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"돈은? 액수 제대로 찔러 준 거 맞아?","JPN":"金は？　ちゃんと渡したのか？","ENG":"Huh? What about the money? Did you make sure to give the right amount?","TWN":"錢呢？錢給得夠多吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"이것들, 용병들이랍시고 세상 모르고 설치는군.","JPN":"こいつら、傭兵だからってなんでも許されると思ってるな。","ENG":"Look, you mercenaries don’t seem to know how the world works.","TWN":"你們這些傭兵真是不長眼睛！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"뇌물공여는 중죄라는 걸 모르나? 전부 차에서 내려!","JPN":"贈賄は重罪であることを知らないのか？　全員車から降りろ！","ENG":"Aren’t you even aware that bribery is a felony? Everybody, out of the car, now!","TWN":"難道不知道賄賂是重罪嗎？立刻給我下車！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"떽떽거리지 마. 총각.","JPN":"つべこべうるさいぞ。若造。","ENG":"Shh, quiet down, young man.","TWN":"小夥子，少在那邊大呼小叫的！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_D","text":{"KOREA":"비, 비상! 비상! 당장 상부에 연락……!","JPN":"ひ、非常事態！　非常事態だ！　今すぐ上層部に連絡を……！","ENG":"Em-Emergency! It’s an emergency! Call for backup—!","TWN":"注…注意！緊急狀況！立刻通報上……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_E","text":{"KOREA":"도, 도망쳐! 부대에 알려!","JPN":"に、逃げろ！　部隊に知らせろ！","ENG":"R-Run! Tell the others!","TWN":"快…快逃！通知部隊！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_E","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_F","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_F","text":{"KOREA":"히, 히익……!?","JPN":"ひ、ひいっ……！？","ENG":"E-Eeek...!?","TWN":"唔……！？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_E","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_F","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"뭘 굽실거리고 앉았어. 반군이란 녀석이.","JPN":"何へいこらしてる。反乱軍なんだろう。","ENG":"What were you going on about? Rebel scum.","TWN":"你不是叛軍嗎？幹嘛在那邊低聲下氣的！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"어차피 지금은 침식체 때문에 이런 데 신경도 못 써. 얼른 차에 타.","JPN":"どうせ今は侵食体のおかげでこんな所には気も止めない。早く車に乗れ。","ENG":"Anyways, because of Corrupted Objects, there’s no need to do this quietly. Quick. Get in the car.","TWN":"反正政府那邊正忙著應付侵蝕體，才沒多餘的心思管這裡。快上車！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……. 그야 저놈들 머릿수가 좀 되니까.","JPN":"へ、へへ……だってあいつら、人数が結構いたから。","ENG":"Heh, heh heh... There’s quite a lot of these guys.","TWN":"嘿嘿嘿……因為他們人數有點多嘛～"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"한 발에 한 놈씩 해치우다니, 굉장하잖아.","JPN":"一人一発ずつでやるなんて、すごいな。","ENG":"One shot, one kill for each of them. Incredible.","TWN":"你一發子彈就幹掉一個欸，超威的！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"내 친구들은 다들 눈 감고도 하던 일이야. 운전이나 제대로 해.","JPN":"私の知り合いはみんな目をつむった状態でもやれたことだ。ちゃんと運転しろ。","ENG":"My other friends could have taken care of something like this with their eyes closed. Just drive.","TWN":"這點小事我那些朋友閉著眼睛也辦得到，開你的車吧。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤헤, 꽉 잡으라고. 신나게 밟을 테니까.","JPN":"へへ、しっかり掴まってろよ。思いっきり飛ばすから。","ENG":"Heh heh... Hold on tight. Let’s see how fast this thing can go.","TWN":"嘿嘿，抓緊囉，我要加速囉！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"}}}}]`);export{e as default};